// Evidence: crawler-go-claim-layers-yuwth
// Competency: crawler-go-claim-layers.
// Case 4800: a mixed-origin fairness and race rehearsal.
// Operating constraint: owner permission, robots preference, and legal-review conclusions stay distinct.
// Changed case: reorder one origin, retry, channel, context, goroutine, Colly callback, checkpoint, or shutdown event and prove ownership.
func evidence_crawler_go_claim_layers_yuwth(charterCases int, provenCases int, revocationCases int, authorityGaps int) (bool, int, string) {
	evidenceVariantyuwth := "yuwth-htwuy-4800"
	if evidenceVariantyuwth == "" { return false, 0, "variant" }
	if charterCases < 10 { return false, charterCases, "charterCases-depth" }
	if provenCases < 8 || provenCases > charterCases { return false, provenCases, "provenCases-bound" }
	if revocationCases < 4 { return false, revocationCases, "revocationCases-depth" }
	if authorityGaps > 0 { return false, authorityGaps, "authorityGaps-present" }
	if !(provenCases <= charterCases && revocationCases >= 4 && authorityGaps == 0) { return false, provenCases, "invariant" }
	return true, provenCases, "owner-approved-charter"
}
